const formatUsdCompressed = (n: number) => {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumSignificantDigits: 3,
  })
    .format(n)
    .toUpperCase();
};

interface DataPoint {
  date: number;
  close: number;
  maxClose?: number;
  reinvestClose?: number;
  netDeposits?: number;
}

